/**
 * Email Sender Service - Gmail Integration
 * Actually sends emails generated by Ollama AI
 */

const nodemailer = require('nodemailer');
const { run, get, all } = require('../db/database');

let transporter = null;

/**
 * Initialize Gmail transporter
 */
function initEmailSender() {
  if (transporter) return transporter;

  const smtpConfig = {
    host: process.env.SMTP_HOST || 'smtp.gmail.com',
    port: parseInt(process.env.SMTP_PORT || '587'),
    secure: false, // true for 465, false for other ports
    auth: {
      user: process.env.SMTP_USER || '',
      pass: process.env.SMTP_PASS || ''
    }
  };

  transporter = nodemailer.createTransport(smtpConfig);

  // Verify connection
  transporter.verify((error, success) => {
    if (error) {
      console.error('❌ Gmail connection error:', error.message);
      console.log('⚠️  Email sending disabled - check SMTP credentials');
    } else {
      console.log('✅ Gmail connected successfully - Email sending ENABLED');
    }
  });

  return transporter;
}

/**
 * Send email through Gmail
 */
async function sendEmail(emailData) {
  if (!transporter) {
    initEmailSender();
  }

  // Check if email sending is enabled
  if (process.env.ENABLE_EMAIL_SENDING !== 'true') {
    console.log('[EMAIL] Sending disabled - logging only');
    return logEmailOnly(emailData);
  }

  try {
    const mailOptions = {
      from: `"${process.env.FROM_NAME || 'SurfTrans AI'}" <${process.env.SMTP_USER || process.env.FROM_EMAIL}>`,
      to: emailData.to_email,
      subject: emailData.subject,
      html: emailData.body,
      text: emailData.body.replace(/<[^>]*>/g, ''), // Plain text fallback
      replyTo: emailData.reply_to || process.env.SMTP_USER
    };

    // Send email
    const result = await transporter.sendMail(mailOptions);
    
    console.log(`[EMAIL] ✅ Sent to ${emailData.to_email}: ${emailData.subject}`);

    // Log in database
    logEmail({
      ...emailData,
      status: 'sent',
      sent_at: new Date().toISOString(),
      message_id: result.messageId
    });

    return {
      success: true,
      messageId: result.messageId,
      sent_at: new Date().toISOString()
    };
  } catch (error) {
    console.error(`[EMAIL] ❌ Failed to send to ${emailData.to_email}:`, error.message);
    
    // Log failure
    logEmail({
      ...emailData,
      status: 'failed',
      error: error.message
    });

    return {
      success: false,
      error: error.message
    };
  }
}

/**
 * Send bulk emails (for campaigns)
 */
async function sendBulkEmails(emails) {
  const results = {
    total: emails.length,
    sent: 0,
    failed: 0,
    errors: []
  };

  // Send emails with delay to avoid spam detection
  for (const email of emails) {
    try {
      const result = await sendEmail(email);
      
      if (result.success) {
        results.sent++;
      } else {
        results.failed++;
        results.errors.push({
          to: email.to_email,
          error: result.error
        });
      }

      // Add delay between emails (1-3 seconds)
      await new Promise(resolve => 
        setTimeout(resolve, 1000 + Math.random() * 2000)
      );
    } catch (error) {
      results.failed++;
      results.errors.push({
        to: email.to_email,
        error: error.message
      });
    }
  }

  console.log(`[EMAIL BULK] Sent: ${results.sent}/${results.total}, Failed: ${results.failed}`);
  return results;
}

/**
 * Send outreach email to lead
 */
async function sendOutreachEmail(lead, emailContent) {
  return await sendEmail({
    to_email: lead.email,
    subject: emailContent.subject,
    body: emailContent.body,
    type: 'outreach',
    shipper_id: lead.id,
    ai_generated: true
  });
}

