/**
 * Log email in database
 */
function logEmail(emailData) {
  const { v4: uuidv4 } = require('uuid');
  const id = uuidv4();
  
  run(`INSERT INTO ai_emails 
       (id, load_id, shipper_id, carrier_id, from_email, to_email, subject, body, type, status, ai_generated, sent_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    [
      id,
      emailData.load_id || null,
      emailData.shipper_id || null,
      emailData.carrier_id || null,
      emailData.from_email || process.env.SMTP_USER,
      emailData.to_email,
      emailData.subject,
      emailData.body,
      emailData.type || 'outreach',
      emailData.status || 'sent',
      emailData.ai_generated !== false ? 1 : 0,
      emailData.sent_at || new Date().toISOString()
    ]
  );
  
  return id;
}

/**
 * Log email only (without sending - for testing)
 */
function logEmailOnly(emailData) {
  const id = logEmail({
    ...emailData,
    status: 'draft'
  });
  
  console.log(`[EMAIL LOGGED] ${emailData.to_email}: ${emailData.subject}`);
  return { success: true, logged: true, id };
}

/**
 * Get email statistics
 */
function getEmailStats(days = 30) {
  return all(`
    SELECT 
      type,
      status,
      COUNT(*) as count
    FROM ai_emails
    WHERE created_at >= date('now', ?)
    GROUP BY type, status
    ORDER BY count DESC
  `, [`-${days} days`]);
}

/**
 * Get sent emails
 */
function getSentEmails(limit = 50) {
  return all(`
    SELECT e.*, s.company_name as shipper_name
    FROM ai_emails e
    LEFT JOIN shippers s ON e.shipper_id = s.id
    WHERE e.status = 'sent'
    ORDER BY e.sent_at DESC
    LIMIT ?
  `, [limit]);
}

/**
 * Track email opens (if tracking enabled)
 */
function trackEmailOpen(messageId) {
  run(`UPDATE ai_emails SET opened_at = datetime('now') WHERE message_id = ?`, [messageId]);
}

/**
 * Test Gmail connection
 */
async function testConnection() {
  try {
    if (!transporter) {
      initEmailSender();
    }
    
    await transporter.verify();
    return {
      success: true,
      message: 'Gmail connection successful',
      user: process.env.SMTP_USER
    };
  } catch (error) {
    return {
      success: false,
      message: error.message,
      setup_help: `
        1. Enable 2-Step Verification in Gmail
        2. Generate App Password: https://myaccount.google.com/apppasswords
        3. Update .env with:
           SMTP_USER=your-email@gmail.com
           SMTP_PASS=your-16-char-app-password
           ENABLE_EMAIL_SENDING=true
      `
    };
  }
}

module.exports = {
  initEmailSender,
  sendEmail,
  sendBulkEmails,
  sendOutreachEmail,
  sendFollowUpEmail,
  sendQuoteEmail,
  sendNegotiationEmail,
  sendConfirmationEmail,
  logEmail,
  getEmailStats,
  getSentEmails,
  trackEmailOpen,
  testConnection
};
